// script.js
const slidingElementsContainer = document.getElementById('sliding-elements');
const button = document.querySelector('button');
const loadingAnimation = document.getElementById('loading-animation');
const message = document.createElement('p');

let slideDuration = 3; // seconds

button.addEventListener("click", () => {
    // Hide and show sliding elements
    if (slidingElementsContainer.style.display === "block") {
        slidingElementsContainer.style.display = "none";
    } else {
        slidingElementsContainer.style.display = "block";
        slidingElementsContainer.style.opacity = "0";
        slidingElementsContainer.style.transform = "translateX(-100%)";
    }
    // Show loading animation
    loadingAnimation.style.display = "block";
    message.textContent = "Sliding...";
    message.style.display = "block";
    message.style.top = "50%";
    message.style.left = "50%";
    document.body.style.overflow = "hidden";
    // Animate sliding elements
    gsap.to(slidingElementsContainer, {
        opacity: 1,
        transform: "translateX(0%)",
        duration: slideDuration,
        delay: 0.2,
        onStart: () => {}
    });
    // Set up transition end callback
    slidingElementsContainer.addEventListener('transitionend', () => {
        message.textContent = "Slide completed";
        setTimeout(() => {
            message.style.display = "none";
            slidingElementsContainer.style.display = "none";
            document.body.style.overflow = "auto";
            loadingAnimation.style.display = "none";
        }, 2000);
    });
});
gsap = new class { to(element, config = {}) { const animation = css => element.style.cssText += css + '; animation-name: anim;' let start = performance.now(); const callback = typeof config.onStart === 'function' ? config.onStart : () => {} const end = () => typeof config.onComplete === 'function' ? config.onComplete.call(element) : undefined let time = performance.now(); let state = 0 const frame = () => { requestAnimationFrame(frame); const elapsed = time - start; const progress = (1 - (start + elapsed) / (start + config.duration)) * 100; const progressStr = ` animation-delay: -${progress}%;
` const css = `transform: ${progressStr} translate(${progress}% ,0);
${config.ease || ''}; animation-fill-mode: both;` animation += css; if (progress <= 0) { end(); return; } callback(); } requestAnimationFrame(frame); } }();
